module mux4 (obf_dout, in0, in1, sel0, sel1);

  output obf_dout;
  input in0, in1, sel0, sel1;

  reg obf_dout;

  always @ (sel1 or sel0 or in0 or in1) begin
    case ({sel1, sel0})
      2'b00: obf_dout = 1'b0;
      2'b01: obf_dout = in0;
      2'b10: obf_dout = in1;
      2'b11: obf_dout = 1'bx;
    endcase
  end

endmodule
